// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import java.util.List;
import java.util.Map;
import java.util.function.Function;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.common.annotation.Experimental;
import org.eclipse.rdf4j.query.algebra.BinaryTupleOperator;
import org.eclipse.rdf4j.query.algebra.QueryModelNode;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.UnaryTupleOperator;
import org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor;
import org.eclipse.rdf4j.query.explanation.TelemetryMetricNames;

/**
 * Writes planner-owned provenance onto the selected materialized algebra tree. This class never recomputes estimates.
 */
@Experimental
public final class CascadesPlanProvenanceAnnotator {
	private static final String EXACT_JOIN_SURFACE_PREFIX = "optimizer.exactJoinSurface";
	private static final String CASCADES_RULE = "optimizer.cascadesRule";
	private static final String CASCADES_RULE_KIND = "optimizer.cascadesRuleKind";
	private static final String CASCADES_PROOFS = "optimizer.cascadesProofs";
	private static final String CASCADES_REJECTIONS = "optimizer.cascadesRejectedAlternatives";
	private static final String CASCADES_COVERED_BY_WINNER = "optimizer.cascadesCoveredByWinner";
	private static final String COVERED_BY_PARENT_WINNER = "covered_by_parent_winner";
	private static final String FALLBACK_NO_WINNER = "fallback_no_winner";
	private static final String PLANNED_CARDINALITY_Q_ERROR = "plannedCardinalityQError";
	private static final String PLANNED_COST_ROW_Q_ERROR_MAX = "plannedCostRowQErrorMax";
	private static final String PLANNED_COST_WORK_Q_ERROR_MAX = "plannedCostWorkQErrorMax";
	private static final CostVector DEFAULT_FALLBACK_COST = new CostVector(1.0d, 1.0d, 0.0d, 0.0d, 0.0d,
			4.0d, 4.0d, 4.0d, 4.0d, 3.0d, 0.0d, 0.0d);

	private CascadesPlanProvenanceAnnotator() {
	}

	public static void annotate(Winner winner) {
		if (winner != null) {
			annotate(winner.plan(), winner.provenance());
		}
	}

	public static void annotate(TupleExpr plan, PlanProvenance provenance) {
		annotate(plan, provenance, null);
	}

	public static void annotate(TupleExpr plan, PlanProvenance provenance, String plannerIdOverride) {
		if (plan == null || provenance == null) {
			return;
		}
		sanitizeSubtree(plan);
		annotateRecursive(plan, provenance, plannerIdOverride);
	}

	public static void sanitize(TupleExpr plan) {
		if (plan != null) {
			sanitizeSubtree(plan);
		}
	}

	public static void annotateFallback(TupleExpr plan, String plannerId, String source, String usage,
			CostVector fallbackCost) {
		annotateFallback(plan, plannerId, source, usage, ignored -> fallbackCost);
	}

	public static void annotateFallback(TupleExpr plan, String plannerId, String source, String usage,
			Function<TupleExpr, CostVector> fallbackCostProvider) {
		if (plan == null) {
			return;
		}
		plan.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				if (node instanceof TupleExpr tupleExpr) {
					annotateFallbackNode(tupleExpr, plannerId, source, usage, fallbackCostProvider);
				}
				node.visitChildren(this);
			}
		});
	}

	private static CostVector fallbackCost(TupleExpr tupleExpr, Function<TupleExpr, CostVector> fallbackCostProvider) {
		if (fallbackCostProvider != null) {
			CostVector cost = fallbackCostProvider.apply(tupleExpr);
			if (cost != null) {
				return cost;
			}
		}
		return fallbackCost();
	}

	private static void annotateRecursive(TupleExpr node, PlanProvenance provenance, String plannerIdOverride) {
		if (node == null || provenance == null) {
			return;
		}
		annotateNode(node, provenance, plannerIdOverride);
		List<PlanProvenance> inputs = provenance.inputs();
		if (node instanceof UnaryTupleOperator unary && inputs.size() == 1) {
			annotateRecursive(unary.getArg(), inputs.getFirst(), plannerIdOverride);
		} else if (node instanceof BinaryTupleOperator binary && inputs.size() >= 2) {
			annotateRecursive(binary.getLeftArg(), inputs.get(0), plannerIdOverride);
			annotateRecursive(binary.getRightArg(), inputs.get(1), plannerIdOverride);
		}
		annotateDescendantsCoveredByWinner(node, provenance, plannerIdOverride);
	}

	private static void annotateNode(QueryModelNode node, PlanProvenance provenance, String plannerIdOverride) {
		EstimateSnapshot estimate = provenance.estimate();
		CostVector cost = provenance.cost();
		double plannedRows = finiteOr(estimate.rows(), cost.rows());
		double plannedWorkRows = finiteOr(estimate.workRows(), cost.workRows());
		for (Map.Entry<String, String> entry : estimate.stringMetrics().entrySet()) {
			String value = sanitizeStringMetric(entry.getKey(), entry.getValue());
			if (!skipStringMetric(entry.getKey(), value)) {
				node.setStringMetricPlanned(entry.getKey(), value);
			}
		}
		for (Map.Entry<String, Double> entry : estimate.doubleMetrics().entrySet()) {
			if (!isExactJoinSurfaceMetric(entry.getKey())) {
				node.setDoubleMetricPlanned(entry.getKey(), entry.getValue());
			}
		}
		String plannerId = isBlank(plannerIdOverride) ? estimate.plannerId() : plannerIdOverride;
		String estimateSource = selectedEstimateSource(node, estimate);
		node.setStringMetricPlanned(TelemetryMetricNames.PLANNER_ID, plannerId);
		node.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, estimateSource);
		node.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE, estimate.usage());
		node.setStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_DECISION_ID,
				provenance.ruleId() + ":g" + provenance.memoGroupId() + ":e" + provenance.expressionId());
		node.setStringMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_SHAPE, "vector");
		node.setStringMetricPlanned(TelemetryMetricNames.PLANNED_COST_SHAPE, "vector");
		node.setStringMetricPlanned(CASCADES_RULE, provenance.ruleId());
		node.setStringMetricPlanned(CASCADES_RULE_KIND, provenance.ruleKind().name());
		node.setStringMetricPlanned(CASCADES_PROOFS, proofSummary(provenance.proofs()));
		node.setStringMetricPlanned(CASCADES_REJECTIONS, rejectionSummary(provenance.rejectedAlternatives()));
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, plannedRows);
		node.setResultSizeEstimate(plannedRows);
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_WORK_ROWS, plannedWorkRows);
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, cost.workRows());
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, cost.objectiveScore());
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_UNCERTAINTY_ROWS, cost.uncertaintyRows());
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_COST_UNCERTAINTY_ROWS, cost.uncertaintyRows());
		node.setDoubleMetricPlanned(TelemetryMetricNames.PLANNED_CARDINALITY_CONFIDENCE, cost.confidence());
		node.setDoubleMetricPlanned(PLANNED_CARDINALITY_Q_ERROR, cost.rowQErrorMax());
		node.setDoubleMetricPlanned(PLANNED_COST_ROW_Q_ERROR_MAX, cost.rowQErrorMax());
		node.setDoubleMetricPlanned(PLANNED_COST_WORK_Q_ERROR_MAX, cost.workQErrorMax());
		node.setDoubleMetricPlanned("plannedCascadesEvidenceCount", cost.evidenceCount());
	}

	private static void annotateDescendantsCoveredByWinner(TupleExpr root, PlanProvenance provenance,
			String plannerIdOverride) {
		root.visitChildren(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				if (node instanceof TupleExpr) {
					annotateCoveredNode(node, provenance, plannerIdOverride);
				}
				node.visitChildren(this);
			}
		});
	}

	private static void annotateCoveredNode(QueryModelNode node, PlanProvenance provenance, String plannerIdOverride) {
		String currentUsage = node.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE);
		if (!missingOrFallbackUsage(currentUsage)) {
			return;
		}
		EstimateSnapshot estimate = provenance.estimate();
		String decisionId = decisionId(provenance);
		String plannerId = isBlank(plannerIdOverride) ? estimate.plannerId() : plannerIdOverride;

		setStringIfMissing(node, TelemetryMetricNames.PLANNER_ID, plannerId);
		setStringIfMissing(node, TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, estimate.source());
		setStringIfMissingOrFallback(node, TelemetryMetricNames.PLANNED_ESTIMATE_USAGE, COVERED_BY_PARENT_WINNER);
		setStringIfMissing(node, TelemetryMetricNames.PLANNED_ESTIMATE_DECISION_ID, decisionId + ":covered");
		setStringIfMissing(node, TelemetryMetricNames.PLANNED_CARDINALITY_SHAPE, "vector");
		setStringIfMissing(node, TelemetryMetricNames.PLANNED_COST_SHAPE, "vector");
		setStringIfMissing(node, CASCADES_RULE, provenance.ruleId());
		setStringIfMissing(node, CASCADES_RULE_KIND, provenance.ruleKind().name());
		setStringIfMissing(node, CASCADES_PROOFS, proofSummary(provenance.proofs()));
		setStringIfMissing(node, CASCADES_REJECTIONS, rejectionSummary(provenance.rejectedAlternatives()));
		setStringIfMissing(node, CASCADES_COVERED_BY_WINNER, decisionId);
	}

	private static void annotateFallbackNode(TupleExpr node, String plannerId, String source, String usage,
			Function<TupleExpr, CostVector> fallbackCostProvider) {
		boolean replaceFallbackMetrics = missingOrFallbackUsage(
				node.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE));
		if (!isBlank(plannerId)) {
			node.setStringMetricPlanned(TelemetryMetricNames.PLANNER_ID, plannerId);
		}
		setStringIfMissing(node, TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE,
				isBlank(source) ? "cascades-fallback" : source);
		setStringIfMissing(node, TelemetryMetricNames.PLANNED_ESTIMATE_USAGE,
				isBlank(usage) ? "fallback_no_winner" : usage);
		setStringIfMissing(node, TelemetryMetricNames.PLANNED_CARDINALITY_SHAPE, "vector");
		setStringIfMissing(node, TelemetryMetricNames.PLANNED_COST_SHAPE, "vector");
		if (COVERED_BY_PARENT_WINNER.equals(
				node.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_USAGE))
				|| !fallbackCostRequired(node, replaceFallbackMetrics)) {
			return;
		}
		CostVector cost = fallbackCost(node, fallbackCostProvider);
		setDoubleIfMissingOrFallback(node, TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, cost.rows(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, TelemetryMetricNames.PLANNED_WORK_ROWS, cost.workRows(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, TelemetryMetricNames.PLANNED_COST_WORK_ROWS, cost.workRows(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE, cost.objectiveScore(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, TelemetryMetricNames.PLANNED_UNCERTAINTY_ROWS, cost.uncertaintyRows(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, TelemetryMetricNames.PLANNED_COST_UNCERTAINTY_ROWS,
				cost.uncertaintyRows(), replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, TelemetryMetricNames.PLANNED_CARDINALITY_CONFIDENCE, cost.confidence(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, PLANNED_CARDINALITY_Q_ERROR, cost.rowQErrorMax(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, PLANNED_COST_ROW_Q_ERROR_MAX, cost.rowQErrorMax(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, PLANNED_COST_WORK_Q_ERROR_MAX, cost.workQErrorMax(),
				replaceFallbackMetrics);
		setDoubleIfMissingOrFallback(node, "plannedCascadesEvidenceCount", cost.evidenceCount(),
				replaceFallbackMetrics);
	}

	private static boolean fallbackCostRequired(QueryModelNode node, boolean replaceFallbackMetrics) {
		return replaceFallbackMetrics
				|| missingDoubleMetric(node, TelemetryMetricNames.PLANNED_CARDINALITY_ROWS)
				|| missingDoubleMetric(node, TelemetryMetricNames.PLANNED_WORK_ROWS)
				|| missingDoubleMetric(node, TelemetryMetricNames.PLANNED_COST_WORK_ROWS)
				|| missingDoubleMetric(node, TelemetryMetricNames.PLANNED_OBJECTIVE_SCORE)
				|| missingDoubleMetric(node, TelemetryMetricNames.PLANNED_UNCERTAINTY_ROWS)
				|| missingDoubleMetric(node, TelemetryMetricNames.PLANNED_COST_UNCERTAINTY_ROWS)
				|| missingDoubleMetric(node, TelemetryMetricNames.PLANNED_CARDINALITY_CONFIDENCE)
				|| missingDoubleMetric(node, PLANNED_CARDINALITY_Q_ERROR)
				|| missingDoubleMetric(node, PLANNED_COST_ROW_Q_ERROR_MAX)
				|| missingDoubleMetric(node, PLANNED_COST_WORK_Q_ERROR_MAX)
				|| missingDoubleMetric(node, "plannedCascadesEvidenceCount");
	}

	private static boolean missingDoubleMetric(QueryModelNode node, String metricName) {
		double current = node.getDoubleMetricPlanned(metricName);
		return !Double.isFinite(current) || current < 0.0d;
	}

	private static void sanitizeSubtree(TupleExpr root) {
		root.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			protected void meetNode(QueryModelNode node) {
				sanitizeNode(node);
				node.visitChildren(this);
			}
		});
	}

	private static void sanitizeNode(QueryModelNode node) {
		removeStringMetrics(node);
		removeDoubleMetrics(node);
		removeLongMetrics(node);
	}

	private static void removeStringMetrics(QueryModelNode node) {
		Map<String, String> metrics = node.getStringMetricsPlanned();
		if (metrics.isEmpty()) {
			return;
		}
		try {
			metrics.replaceAll(CascadesPlanProvenanceAnnotator::sanitizeStringMetric);
			metrics.entrySet()
					.removeIf(entry -> isExactJoinSurfaceMetric(entry.getKey())
							|| TelemetryMetricNames.PLANNED_ESTIMATE_USAGE.equals(entry.getKey())
									&& TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_EXPLAIN_RECOMPUTED
											.equals(entry.getValue()));
		} catch (UnsupportedOperationException ignored) {
			// immutable no-op node metrics
		}
	}

	private static void removeDoubleMetrics(QueryModelNode node) {
		Map<String, Double> metrics = node.getDoubleMetricsPlanned();
		if (metrics.isEmpty()) {
			return;
		}
		try {
			metrics.keySet().removeIf(CascadesPlanProvenanceAnnotator::isExactJoinSurfaceMetric);
		} catch (UnsupportedOperationException ignored) {
			// immutable no-op node metrics
		}
	}

	private static void removeLongMetrics(QueryModelNode node) {
		Map<String, Long> metrics = node.getLongMetricsPlanned();
		if (metrics.isEmpty()) {
			return;
		}
		try {
			metrics.keySet().removeIf(CascadesPlanProvenanceAnnotator::isExactJoinSurfaceMetric);
		} catch (UnsupportedOperationException ignored) {
			// immutable no-op node metrics
		}
	}

	private static boolean skipStringMetric(String name, String value) {
		return isExactJoinSurfaceMetric(name)
				|| TelemetryMetricNames.PLANNED_ESTIMATE_USAGE.equals(name)
						&& TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_EXPLAIN_RECOMPUTED.equals(value);
	}

	private static String sanitizeStringMetric(String name, String value) {
		if (TelemetryMetricNames.OPTIMIZER_LOGICAL_EXPLORATION.equals(name) && value != null) {
			int verboseFrontier = value.indexOf(", finalFrontier=");
			if (verboseFrontier >= 0) {
				return value.substring(0, verboseFrontier);
			}
			int verboseConsidered = value.indexOf(", considered=");
			if (verboseConsidered >= 0) {
				return value.substring(0, verboseConsidered);
			}
			int verboseRejected = value.indexOf(", rejected=");
			if (verboseRejected >= 0) {
				return value.substring(0, verboseRejected);
			}
		}
		return value;
	}

	private static boolean isExactJoinSurfaceMetric(String name) {
		return name != null && name.startsWith(EXACT_JOIN_SURFACE_PREFIX);
	}

	private static void setStringIfMissing(QueryModelNode node, String metricName, String value) {
		String current = node.getStringMetricPlanned(metricName);
		if (isBlank(current) || TelemetryMetricNames.PLANNED_ESTIMATE_USAGE.equals(metricName)
				&& TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_EXPLAIN_RECOMPUTED.equals(current)) {
			node.setStringMetricPlanned(metricName, value);
		}
	}

	private static void setStringIfMissingOrFallback(QueryModelNode node, String metricName, String value) {
		String current = node.getStringMetricPlanned(metricName);
		if (isBlank(current)
				|| TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_EXPLAIN_RECOMPUTED.equals(current)
				|| FALLBACK_NO_WINNER.equals(current)) {
			node.setStringMetricPlanned(metricName, value);
		}
	}

	private static void setDoubleIfMissing(QueryModelNode node, String metricName, double value) {
		double current = node.getDoubleMetricPlanned(metricName);
		if (!Double.isFinite(current) || current < 0.0d) {
			node.setDoubleMetricPlanned(metricName, value);
		}
	}

	private static void setDoubleIfMissingOrFallback(QueryModelNode node, String metricName, double value,
			boolean replaceFallbackMetrics) {
		if (replaceFallbackMetrics) {
			node.setDoubleMetricPlanned(metricName, value);
		} else {
			setDoubleIfMissing(node, metricName, value);
		}
	}

	private static boolean isBlank(String value) {
		return value == null || value.isBlank();
	}

	private static double finiteOr(double value, double fallback) {
		return Double.isFinite(value) && value >= 0.0d ? value : fallback;
	}

	private static boolean missingOrFallbackUsage(String usage) {
		return isBlank(usage)
				|| TelemetryMetricNames.PLANNED_ESTIMATE_USAGE_EXPLAIN_RECOMPUTED.equals(usage)
				|| FALLBACK_NO_WINNER.equals(usage);
	}

	private static String selectedEstimateSource(QueryModelNode node, EstimateSnapshot estimate) {
		String existing = node.getStringMetricPlanned(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE);
		if (isCostOnlyCascadesSource(estimate) && isSpecificSource(existing)) {
			return existing;
		}
		return estimate.source();
	}

	private static boolean isCostOnlyCascadesSource(EstimateSnapshot estimate) {
		return estimate != null
				&& "cascades".equals(estimate.source())
				&& estimate.stringMetrics().isEmpty()
				&& estimate.doubleMetrics().isEmpty();
	}

	private static boolean isSpecificSource(String source) {
		return !isBlank(source)
				&& !"cascades".equals(source)
				&& !"cascades-fallback".equals(source)
				&& !"lmdb-cascades-fallback".equals(source);
	}

	private static String decisionId(PlanProvenance provenance) {
		return provenance.ruleId() + ":g" + provenance.memoGroupId() + ":e" + provenance.expressionId();
	}

	private static CostVector fallbackCost() {
		return DEFAULT_FALLBACK_COST;
	}

	private static String proofSummary(List<RuleProof> proofs) {
		if (proofs == null || proofs.isEmpty()) {
			return "";
		}
		return proofs.stream()
				.map(RuleProof::metricFragment)
				.collect(Collectors.joining("; "));
	}

	private static String rejectionSummary(List<RejectedAlternative> rejections) {
		if (rejections == null || rejections.isEmpty()) {
			return "";
		}
		return rejections.stream()
				.map(CascadesPlanProvenanceAnnotator::rejectionSummary)
				.collect(Collectors.joining("; "));
	}

	private static String rejectionSummary(RejectedAlternative rejection) {
		StringBuilder summary = new StringBuilder()
				.append(rejection.ruleId())
				.append(":")
				.append(rejection.reason())
				.append(":");
		if (!rejection.missingProperties().isEmpty()) {
			summary.append("missing=")
					.append(String.join(",", rejection.missingProperties()))
					.append(":");
		}
		return summary.append("score=")
				.append(rejection.cost().objectiveScore())
				.toString();
	}
}
